import json
import sys

def run(payload):
    findings = []
    for item in payload.get('items', []):
        spec = item.get('spec', {})
        if item.get('metadata', {}).get('namespace') == 'default':
            findings.append({'severity': 'medium', 'message': 'Workload uses default namespace'})
        for c in spec.get('containers', []):
            if 'resources' not in c:
                findings.append({'severity': 'high', 'message': f"Container {c.get('name', 'unknown')} has no resources block"})
    return {'findings': findings}

if __name__ == '__main__':
    payload = json.load(sys.stdin)
    print(json.dumps(run(payload)))
